          import sailpoint.object.Custom;
          import sailpoint.object.Identity;
          import sailpoint.tools.Util;

          trace(logName, "Ascension-Workflow-Lifecycle-Rehire start for identity: " + identityName);

          trace(logName, "Entering Step: "+wfcontext.getStep().getName());

          List ministryNames = new ArrayList();
          String ministryValue= "";
          boolean transitionVal = false;

          try{

          Identity identity = context.getObjectByName(Identity.class,identityName);                 
          Custom custom = context.getObjectByName(Custom.class, "Ascension-custom-generalConfiguration");       

          if(null != identity){
          ministryValue = identity.getAttribute("ministry");
                   

          if(custom != null && custom.get("domainworkitemministry") !=null){
          ministryNames = custom.get("domainworkitemministry");         
          }

          if(null != ministryNames && !ministryNames.isEmpty() && ministryNames.contains(ministryValue)){
          transitionVal = true;
          }
           //comment decache //context.decache(identity);
          }
          
          if(null != custom){
          //comment decache //context.decache(custom);
          }
          } catch(Exception ex){
          addError(wfcontext, "Error in step - " + wfcontext.getStep().getName() + " : " + ex);
          throw new Exception(ex.getMessage());
          }

          trace(logName, "Exiting Step: "+wfcontext.getStep().getName());

          return transitionVal;

